def encode(message):
    vowels = 'aeiouAEIOU'
    vowel_map = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    result = []
    for char in message:
        if char in vowels:
            result.append(vowel_map[char])
        else:
            result.append(char.swapcase())

    return ''.join(result)
